#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_CLEAR_THRESHOLD_NTU 35
#define CONTROLLER_SETTLING_RESET_THRESHOLD_NTU 40
#define CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU 50
#define CONTROLLER_MIN_PROCESS_LEVEL 40
#define CONTROLLER_COMPLETE_LEVEL 15
#define CONTROLLER_CLEAR_STREAK_REQUIRED 3
#define CONTROLLER_SETTLING_MS 400U
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TURBIDITY,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TURBIDITY,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILTERING,
    CONTROLLER_STATE_SETTLING,
    CONTROLLER_STATE_DRAINING,
    CONTROLLER_STATE_COMPLETE,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int turbidity_ntu;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool filter_on;
    bool drain_open;
    controller_state_t state;
    bool has_valid_turbidity;
    int last_turbidity_ntu;
    uint32_t last_turbidity_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
    int clear_streak_count;
    uint32_t settling_started_ms;
} controller_t;

typedef struct {
    bool filter_on;
    bool drain_open;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Check for sensor timeout - if either sensor is stale (>1000ms), go to safe idle */
    bool sensor_timeout = false;
    if (!controller->has_valid_turbidity || controller->last_turbidity_ms == 0U) {
        /* Turbidity sensor has never been seen or is invalid */
        sensor_timeout = true;
    } else if ((uint32_t)(input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        /* Turbidity sensor is stale */
        sensor_timeout = true;
    }

    if (!controller->has_valid_level || controller->last_level_ms == 0U) {
        /* Level sensor has never been seen or is invalid */
        sensor_timeout = true;
    } else if ((uint32_t)(input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        /* Level sensor is stale */
        sensor_timeout = true;
    }

    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle different input types */
    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No new sensor data - check for timeout and stay in current state */
        if (sensor_timeout) {
            controller_set_safe_idle(controller);
        }
        break;

    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Malformed input - go to safe idle */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit timeout signal */
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_TURBIDITY:
        /* Valid turbidity input */
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Update level freshness with current time if not already set */
        if (!controller->has_valid_level) {
            controller->has_valid_level = true;
            controller->last_level = 0;
            controller->last_level_ms = input.now_ms;
        }

        /* Check for complete state (level < 15) */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_set_safe_idle(controller);
        } else {
            /* LEVEL >= 40 condition for processing turbidity */
            bool level_high = controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL;

            switch (controller->state) {
            case CONTROLLER_STATE_SAFE_IDLE:
                /* In safe idle, stay there until both sensors are valid */
                break;

            case CONTROLLER_STATE_FILTERING:
                /* TURB > 35 and LEVEL >= 40 means continue filtering */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && level_high) {
                    /* Keep filter on, stay in FILTERING */
                } else if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU && level_high) {
                    /* Clear turbidity - increment streak */
                    controller->clear_streak_count++;

                    /* Check for transition to SETTLING */
                    if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                        controller->filter_on = false;
                        controller->drain_open = false;
                        controller->state = CONTROLLER_STATE_SETTLING;
                        controller->settling_started_ms = input.now_ms;
                        output.changed = true;
                    }
                } else if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Turb disturbance - reset streak */
                    controller->clear_streak_count = 0;
                }
                break;

            case CONTROLLER_STATE_SETTLING:
                /* Check for disturbance during settling */
                if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                    /* Turb > 40 - reset and return to FILTERING */
                    controller->clear_streak_count = 0;
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_FILTERING;
                    output.changed = true;
                } else if ((uint32_t)(input.now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS &&
                           controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                           level_high) {
                    /* Settled for 400ms with clear turbidity and level >= 40 */
                    controller->filter_on = false;
                    controller->drain_open = true;
                    controller->state = CONTROLLER_STATE_DRAINING;
                    output.changed = true;
                } else {
                    /* Still settling - stay in SETTLING */
                }
                break;

            case CONTROLLER_STATE_DRAINING:
                /* Check for disturbance during draining */
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && level_high) {
                    /* Turb > 50 - close drain, restart filtering */
                    controller->drain_open = false;
                    controller->filter_on = true;
                    controller->clear_streak_count = 0;
                    controller->state = CONTROLLER_STATE_FILTERING;
                    output.changed = true;
                } else {
                    /* Continue draining - stay in DRAINING */
                }
                break;

            case CONTROLLER_STATE_COMPLETE:
