/* Update turbidity freshness with current time if not already set */
if (!controller->has_valid_turbidity) {
    controller->has_valid_turbidity = true;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = input.now_ms;
}

/* Check for complete state (level < 15) */
if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
    controller_set_safe_idle(controller);
} else {
    /* Both sensors are now valid - check if we should start filtering or settling */
    bool level_high = false;
    if (controller->has_valid_level != 0) {
        level_high = controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL;
    }
    if (controller->has_valid_turbidity && controller->has_valid_level &&
        controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && level_high) {
        /* TURB > 35 and LEVEL >= 40 - start filtering */
        controller->filter_on = true;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_FILTERING;
        output.changed = true;
    } else if (controller->has_valid_turbidity && controller->has_valid_level &&
               controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU && level_high) {
        /* TURB <= 35 and LEVEL >= 40 - start settling */
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SETTLING;
        controller->settling_started_ms = input.now_ms;
        output.changed = true;
    } else {
        /* Not enough data or conditions to start filtering/settling */
